const packID = 'pathfinder-monster-core';
const fu = foundry.utils;
const cmapping = await (await fetch('modules/pf2e-community-monster-core-token-pack-mapping/mapping.json')).json();
const tmapping = await (await fetch('modules/pf2e-tokens-bestiaries/map-pf2e.json')).json();
const cMCmap = cmapping[packID];
const tMCmap = tmapping[packID];
const flatPack = Object.entries(fu.flattenObject(tmapping));
const diff = fu.diffObject(tMCmap, cMCmap)
const equals = fu.objectsEqual(cMCmap, diff)
if (!equals) {
  console.warn('Community mapping does not equal its diff with the token pack, aborting.', {cMCmap, diff})
  return;
}
console.warn('Mapping equals diff, continuing...');

const pack = game.packs.get(`pf2e.${packID}`);
const mapKeys = Object.keys(cMCmap)
const docs = await pack.getDocuments({ _id__in: mapKeys });
const finalOut = Object.entries(cMCmap).reduce((acc,[id,data]) => {
  const tokenImg = typeof data?.token === 'object' ? data.token.img : data?.token ?? "";
  const actorImg = data?.actor ?? "";
  const mcDoc = docs.find(d=>d.id === id)
  if (!mcDoc) {
    console.warn('mapping for ID not in monster core: ', id)
    return acc;
  }
  const originalData = flatPack.filter(([key,value]) => [actorImg, tokenImg].includes(value))
  const originalNamesList = flatPack.reduce((acc, [key, value])=>{
    if (![actorImg, tokenImg].includes(value)) return acc;
    const split = key.split('.');
    if (split[0] === "pf2e.pathfinder-monster-core") return acc;
    const pack = game.packs.get(`pf2e.${split[0]}`)
    const indexEntry = pack.index.get(split[1])
    if (acc.find(n=>n.includes(indexEntry.name))) return acc;
    acc.push(`  - ${indexEntry.name} (${pack.metadata.label})`);
    return acc;
  }, []);
  acc.push(`- ${mcDoc.name}, sharing art with \n${originalNamesList.join("\n")}`);
  return acc;
}, [])
console.warn(finalOut.sort().join("\n"))
